import React, { useState } from 'react';
import {
  Box,
  Container,
  Typography,
  Button,
  Grid,
  Card,
  CardContent,
  Divider,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Switch,
  FormControlLabel,
  Chip,
  Accordion,
  AccordionSummary,
  AccordionDetails
} from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import { useTheme } from '@mui/material/styles';
import { Link as RouterLink } from 'react-router-dom';

const PricingPage = () => {
  const theme = useTheme();
  const [annual, setAnnual] = useState(true);

  const handleBillingChange = () => {
    setAnnual(!annual);
  };

  const plans = [
    {
      name: 'Free',
      price: 0,
      description: 'Perfect for trying out Testy',
      features: [
        '5 enhanced testimonials',
        'Client verification',
        'Basic export options',
        'Email support'
      ],
      buttonText: 'Get Started',
      buttonVariant: 'outlined',
      highlight: false
    },
    {
      name: 'Pro',
      price: annual ? 29 : 39,
      description: 'For growing businesses',
      features: [
        'Unlimited testimonials',
        'Client verification',
        'All export options',
        'Priority support',
        'Remove Testy branding',
        'Custom templates'
      ],
      buttonText: 'Upgrade to Pro',
      buttonVariant: 'contained',
      highlight: true
    },
    {
      name: 'Team',
      price: annual ? 79 : 99,
      description: 'For agencies and teams',
      features: [
        'Everything in Pro',
        '5 team members',
        'Client portal',
        'White-label solution',
        'API access',
        'Dedicated support'
      ],
      buttonText: 'Contact Sales',
      buttonVariant: 'outlined',
      highlight: false
    }
  ];

  const faqs = [
    {
      question: 'How does the AI enhancement work?',
      answer: 'Our AI analyzes your client\'s original testimonial to identify key themes, outcomes, and emotional impacts. It then expands these elements into a compelling narrative that highlights the transformation and results while maintaining authenticity.'
    },
    {
      question: 'Is client verification really necessary?',
      answer: 'Yes! Client verification ensures authenticity and builds trust with your audience. It also protects you legally by confirming your client approves the enhanced version. Our one-click verification makes this process seamless.'
    },
    {
      question: 'Can I customize the enhanced testimonials?',
      answer: 'Absolutely. After the AI generates the enhanced version, you can edit it to match your brand voice or add specific details. The client will always verify the final version.'
    },
    {
      question: 'What happens after the free plan limit?',
      answer: 'Once you reach the limit of 5 testimonials on the free plan, you\'ll need to upgrade to continue creating new enhanced testimonials. Your existing testimonials will remain accessible.'
    },
    {
      question: 'Can I cancel my subscription anytime?',
      answer: 'Yes, you can cancel your subscription at any time. You\'ll continue to have access until the end of your billing period.'
    }
  ];

  return (
    <Box>
      {/* Header */}
      <Box 
        sx={{
          pt: 10,
          pb: 6,
          background: 'linear-gradient(to bottom, rgba(93, 95, 239, 0.05), rgba(93, 95, 239, 0))'
        }}
      >
        <Container maxWidth="md">
          <Typography variant="h2" align="center" gutterBottom>
            Simple, transparent pricing
          </Typography>
          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 4 }}>
            Start free, upgrade when you need more. No hidden fees.
          </Typography>

          <Box sx={{ display: 'flex', justifyContent: 'center', mb: 6 }}>
            <FormControlLabel
              control={
                <Switch 
                  checked={annual} 
                  onChange={handleBillingChange} 
                  color="primary"
                />
              }
              label={
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <Typography variant="body1" sx={{ mr: 1 }}>
                    Bill Monthly
                  </Typography>
                  <Typography variant="body1" sx={{ mr: 1 }}>
                    |
                  </Typography>
                  <Typography 
                    variant="body1" 
                    sx={{ 
                      fontWeight: annual ? 600 : 400,
                      color: annual ? 'primary.main' : 'inherit'
                    }}
                  >
                    Bill Annually
                  </Typography>
                  {annual && (
                    <Chip 
                      label="Save 25%" 
                      size="small" 
                      color="secondary" 
                      sx={{ ml: 1, height: 24 }}
                    />
                  )}
                </Box>
              }
              labelPlacement="end"
            />
          </Box>

          <Grid container spacing={4} justifyContent="center">
            {plans.map((plan) => (
              <Grid item xs={12} sm={6} md={4} key={plan.name}>
                <Card 
                  sx={{ 
                    height: '100%', 
                    display: 'flex', 
                    flexDirection: 'column',
                    position: 'relative',
                    transition: 'transform 0.2s ease-in-out, box-shadow 0.2s ease-in-out',
                    borderRadius: 3,
                    border: plan.highlight ? `2px solid ${theme.palette.primary.main}` : '1px solid rgba(0, 0, 0, 0.08)',
                    '&:hover': {
                      transform: 'translateY(-8px)',
                      boxShadow: plan.highlight ? theme.shadows[6] : theme.shadows[2]
                    }
                  }}
                >
                  {plan.highlight && (
                    <Chip 
                      label="Most Popular" 
                      color="secondary"
                      sx={{ 
                        position: 'absolute',
                        top: -12,
                        left: '50%',
                        transform: 'translateX(-50%)',
                        fontWeight: 600
                      }}
                    />
                  )}

                  <CardContent sx={{ p: 4, flexGrow: 1 }}>
                    <Typography variant="h5" component="h2" gutterBottom>
                      {plan.name}
                    </Typography>

                    <Box sx={{ mb: 2 }}>
                      <Typography variant="h3" component="span">
                        ${plan.price}
                      </Typography>
                      {plan.price > 0 && (
                        <Typography variant="subtitle1" component="span" color="text.secondary">
                          /{annual ? 'year' : 'month'}
                        </Typography>
                      )}
                    </Box>

                    <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                      {plan.description}
                    </Typography>

                    <Divider sx={{ my: 2 }} />

                    <List sx={{ mb: 2 }}>
                      {plan.features.map((feature) => (
                        <ListItem key={feature} sx={{ px: 0, py: 1 }}>
                          <ListItemIcon sx={{ minWidth: 36 }}>
                            <CheckCircleIcon color="primary" fontSize="small" />
                          </ListItemIcon>
                          <ListItemText primary={feature} />
                        </ListItem>
                      ))}
                    </List>
                  </CardContent>

                  <Box sx={{ p: 3, pt: 0 }}>
                    <Button
                      fullWidth
                      variant={plan.buttonVariant}
                      color={plan.highlight ? 'secondary' : 'primary'}
                      component={RouterLink}
                      to={plan.name === 'Free' ? '/enhance' : '#'}
                      sx={{ py: 1.5 }}
                    >
                      {plan.buttonText}
                    </Button>
                  </Box>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Container>
      </Box>

      {/* FAQ Section */}
      <Container maxWidth="md" sx={{ py: 10 }}>
        <Typography variant="h3" align="center" gutterBottom>
          Frequently Asked Questions
        </Typography>
        <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 6 }}>
          Everything you need to know about Testy
        </Typography>

        <Box sx={{ maxWidth: 800, mx: 'auto' }}>
          {faqs.map((faq, index) => (
            <Accordion 
              key={index} 
              elevation={0}
              sx={{ 
                mb: 2, 
                border: '1px solid rgba(0, 0, 0, 0.08)',
                borderRadius: '12px !important',
                '&:before': {
                  display: 'none',
                },
                '&.Mui-expanded': {
                  margin: '0 0 16px 0',
                }
              }}
            >
